mapper.select:
    	SELECT
	    	CASE
	        	WHEN EXISTS (
	            	SELECT 1
	            	FROM vw_user_pass v
	            	WHERE v.user_account_id = #{userAccountId}
	              	AND v.trainer_account_id = #{trainerAccountId}
	        	)
	        	AND NOT EXISTS (
	            	SELECT 1
	            	FROM trainers_reviews r
	            	WHERE r.user_account_id = #{userAccountId}
	              	AND r.trainer_account_id = #{trainerAccountId}
	        	)
	        	THEN 1
	        	ELSE 0
	    	END AS canReview
		FROM dual
